<?php namespace App\Domains\Apparel\Policies; use Illuminate\Auth\Access\HandlesAuthorization; class ClothingPolicy { use HandlesAuthorization; public function viewAny($user) { return true; } public function view($user, $clothing) { return $user->tenant_id === $clothing->tenant_id; } public function create($user) { return true; } public function update($user, $clothing) { return $user->tenant_id === $clothing->tenant_id; } public function delete($user, $clothing) { return $user->tenant_id === $clothing->tenant_id; } }
